    def _compress(self, value: Any) -> Any:
        """Serialize and optionally compress `value` for on-disk storage.

        When no compression codec is configured, the value is stored as-is, letting diskcache
        pickle it natively (preserving compatibility with legacy uncompressed entries).
        """
        if self.compress is None:
            return value

        payload = cloudpickle.dumps(value)
        if self.compress == "gzip":
            payload = gzip.compress(payload)
        elif self.compress == "zlib":
            payload = zlib.compress(payload)
        codec_byte = bytes([_COMPRESSION_CODECS[self.compress]])
        return _COMPRESSION_MAGIC + codec_byte + payload

    def _decompress(self, response: Any) -> Any:
        """Reverse `_compress`, if `response` is a compressed disk cache entry.

        Values that aren't bytes-like, or that don't start with the compression magic header,
        are returned unchanged. This covers legacy entries written before compression support
        was added, as well as ordinary non-bytes cached objects.
        """
        if not isinstance(response, (bytes, bytearray)) or bytes(response[:4]) != _COMPRESSION_MAGIC:
            return response

        codec = response[4]
        payload = bytes(response[5:])
        if codec == _COMPRESSION_CODECS["gzip"]:
            payload = gzip.decompress(payload)
        elif codec == _COMPRESSION_CODECS["zlib"]:
            payload = zlib.decompress(payload)
        return cloudpickle.loads(payload)

    def set_compression(self, compress: Optional[str]) -> None:
        """Set the compression codec used for future disk cache writes.

        Does not retroactively rewrite existing entries.
